        operationReference
            .takeUnless { it.nextCodeSibling()?.elementType == BINARY_EXPRESSION }
            ?.let {
                val stopAtOperationReferenceLeaf = operationReference.firstChildLeafOrSelf()
                maxLineLength <=
                    it
                        .leavesOnLine()
                        .takeWhile { leaf -> leaf != stopAtOperationReferenceLeaf }
                        .lengthWithoutNewlinePrefix()
            }
            ?: false ||
            exceedsMaxLineLengthAfterWrappingOnElvisOperator(operationReference)

    private fun exceedsMaxLineLengthAfterWrappingOnElvisOperator(operationReference: ASTNode): Boolean {
        // The ChainWrappingRule never allows the elvis operator to be wrapped at the end of a line. Wrapping after the elvis operator only
        // makes sense when it is certain that the result will be valid according to the ChainWrappingRule. In case the right-hand side of
        // the elvis operator is still exceeding the max-line-length when it is preceded by the elvis operator, then wrapping should not be
        // autocorrected as it results in a conflict with ChainWrappingRule that can not be resolved.
        if (operationReference.firstChildLeafOrSelf().elementType != ELVIS) {
            return false
        }
        val rightHandSide = operationReference.nextCodeSibling() ?: return false
        val rightHandSideLength =
            rightHandSide
                .firstChildLeafOrSelf()
                .leavesIncludingSelf()
                .takeWhile { it.prevLeafOnSameLineOrNull() != null }
                .sumOf { it.text.length }
        // When wrapped:
        //     val foobar = leftHandSize
        //         ?: rightHandSide
        // The length of the line containing the right hand side is calculated as
        //     length of indent + "?: ".length + rightHandSideLength
        val lengthAfterWrapping =
            indentConfig.childIndentOf(operationReference).length +
                "?: ".length +
                rightHandSideLength
        return lengthAfterWrapping > maxLineLength
    }

