        prevSibling()
            ?.lastChildLeafOrSelf()
            ?.let { prevLeaf ->
                if (prevLeaf.text.contains('\n')) {
                    null
                } else {
                    prevLeaf.prevLeafOnSameLineOrNull() ?: prevLeaf
                }
