{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/BinaryExpressionWrappingElvisIssueTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

/**
 * Test for the issue: "Endless loop in wrapping binary expression after elvis operator"
 * https://github.com/pinterest/ktlint/issues/2296
 *
 * When a line ends with `?:` and the right-hand side expression is long enough that wrapping
 * after the elvis operator would still exceed max line length (because ChainWrappingRule will
 * move `?:` to the start of the next line), ktlint should not try to auto-correct as it
 * would result in an endless loop.
 */
class BinaryExpressionWrappingElvisIssueTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Given a binary expression with elvis operator where right-hand side exceeds max line length when wrapped`() {
        // This is the exact scenario from the issue:
        // The right-hand side (throw UnsupportedOperationException("xxxxxxxxxxx")) is so long that
        // even when placed on a new line with "?: " prefix, it would still exceed max line length.
        // In this case, wrapping should not be auto-corrected to avoid an endless loop with ChainWrappingRule.
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                       $EOL_CHAR
            val foo =
                bar
                    ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .hasLintViolationWithoutAutoCorrect(4, 8, "Line is exceeding max line length")
    }

    @Test
    fun `Given a binary expression with elvis operator where right-hand side fits when wrapped`() {
        // When the right-hand side is short enough that it fits when placed on a new line
        // with "?: " prefix, wrapping should be auto-corrected.
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                   $EOL_CHAR
            val foo =
                bar ?: throw UnsupportedOperationException()
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                   $EOL_CHAR
            val foo =
                bar ?:
                    throw UnsupportedOperationException()
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolation(3, 12, "Line is exceeding max line length. Break line after operator in binary expression")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given original issue scenario with exact code and max line length 60`() {
        // This is the exact test case from the issue report
        val code =
            """
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .withEditorConfigOverride(KtLintAssertThat.MAX_LINE_LENGTH_PROPERTY to 60)
            .addAdditionalRuleProvider { ChainWrappingRule() }
            // The line "        ?: throw UnsupportedOperationException("xxxxxxxxxxx")" would be 60 characters
            // when ChainWrappingRule moves ?: to the start of the line. With indent of 8 + "?: ".length (3) = 11,
            // plus the throw expression, it exceeds 60 characters.
            // So wrapping cannot be auto-corrected.
            .hasLintViolationWithoutAutoCorrect(3, 8, "Line is exceeding max line length")
    }
}
"}

